  // ─── 11. PROTIST PARAPHYLETIC SUPERGROUPS OVERVIEW ────────────────────────
  static protistParaphyleticSupergroups_SAR_Excavata_Amoebozoa_OverviewDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg fill="#000000" version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 500 460" enable-background="new 0 0 500 460" xml:space="preserve">

  <!-- Title -->
  <text x="60" y="20" font-family="Arial" font-size="12" font-weight="bold" fill="#000000">Protist Supergroups — SAR, Excavata, Amoebozoa Overview</text>
  <text x="100" y="34" font-family="Arial" font-size="9" fill="#000000">Protists = paraphyletic grade (not a monophyletic kingdom)</text>

  <!-- ── SAR SUPERGROUP ── -->
  <rect x="20" y="50" width="140" height="180" rx="8" fill="none" stroke="#000000" stroke-width="5"/>
  <text x="44" y="68" font-family="Arial" font-size="11" font-weight="bold" fill="#000000">SAR</text>
  <text x="24" y="82" font-family="Arial" font-size="8" fill="#000000">Stramenopiles + Alveolata</text>
  <text x="30" y="93" font-family="Arial" font-size="8" fill="#000000">+ Rhizaria</text>
  <!-- Stramenopiles box -->
  <rect x="30" y="100" width="120" height="40" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="34" y="114" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Stramenopiles</text>
  <text x="34" y="125" font-family="Arial" font-size="7.5" fill="#000000">Diatoms, brown algae,</text>
  <text x="34" y="135" font-family="Arial" font-size="7.5" fill="#000000">oomycetes (water moulds)</text>
  <!-- Alveolata box -->
  <rect x="30" y="148" width="120" height="38" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="34" y="162" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Alveolata</text>
  <text x="34" y="173" font-family="Arial" font-size="7.5" fill="#000000">Ciliates, Dinoflagellates,</text>
  <text x="34" y="183" font-family="Arial" font-size="7.5" fill="#000000">Apicomplexans (Plasmodium)</text>
  <!-- Rhizaria box -->
  <rect x="30" y="194" width="120" height="28" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="34" y="208" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Rhizaria</text>
  <text x="34" y="218" font-family="Arial" font-size="7.5" fill="#000000">Foraminifera, Radiolaria</text>

  <!-- ── EXCAVATA SUPERGROUP ── -->
  <rect x="180" y="50" width="140" height="180" rx="8" fill="none" stroke="#000000" stroke-width="5"/>
  <text x="214" y="68" font-family="Arial" font-size="11" font-weight="bold" fill="#000000">Excavata</text>
  <text x="186" y="82" font-family="Arial" font-size="8" fill="#000000">Feeding groove (excavation)</text>
  <!-- Diplomonads -->
  <rect x="190" y="92" width="120" height="32" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="194" y="106" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Diplomonads</text>
  <text x="194" y="117" font-family="Arial" font-size="7.5" fill="#000000">Giardia — no mitochondria</text>
  <!-- Parabasalids -->
  <rect x="190" y="130" width="120" height="32" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="194" y="144" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Parabasalids</text>
  <text x="194" y="155" font-family="Arial" font-size="7.5" fill="#000000">Trichomonas — hydrogenosome</text>
  <!-- Euglenozoa -->
  <rect x="190" y="168" width="120" height="54" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="194" y="182" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Euglenozoa</text>
  <text x="194" y="193" font-family="Arial" font-size="7.5" fill="#000000">Euglena — mixotrophic</text>
  <text x="194" y="204" font-family="Arial" font-size="7.5" fill="#000000">Trypanosoma — kinetoplast</text>
  <text x="194" y="215" font-family="Arial" font-size="7.5" fill="#000000">Sleeping sickness vector</text>

  <!-- ── AMOEBOZOA SUPERGROUP ── -->
  <rect x="340" y="50" width="148" height="180" rx="8" fill="none" stroke="#000000" stroke-width="5"/>
  <text x="368" y="68" font-family="Arial" font-size="11" font-weight="bold" fill="#000000">Amoebozoa</text>
  <text x="348" y="82" font-family="Arial" font-size="8" fill="#000000">Lobe-shaped pseudopods</text>
  <!-- Tubulinea -->
  <rect x="350" y="92" width="128" height="34" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="354" y="106" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Tubulinea</text>
  <text x="354" y="117" font-family="Arial" font-size="7.5" fill="#000000">Amoeba proteus — lobose</text>
  <!-- Mycetozoa -->
  <rect x="350" y="132" width="128" height="46" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="354" y="146" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Mycetozoa (slime moulds)</text>
  <text x="354" y="157" font-family="Arial" font-size="7.5" fill="#000000">Dictyostelium — cellular</text>
  <text x="354" y="168" font-family="Arial" font-size="7.5" fill="#000000">Physarum — acellular</text>
  <!-- Entamoeba -->
  <rect x="350" y="184" width="128" height="34" rx="4" fill="none" stroke="#000000" stroke-width="3"/>
  <text x="354" y="198" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Entamoeba</text>
  <text x="354" y="209" font-family="Arial" font-size="7.5" fill="#000000">E. histolytica — amoebiasis</text>

  <!-- ── ARCHAEPLASTIDA (brief) ── -->
  <rect x="100" y="250" width="300" height="50" rx="8" fill="none" stroke="#000000" stroke-width="4" stroke-dasharray="6,3"/>
  <text x="176" y="268" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">Archaeplastida</text>
  <text x="130" y="282" font-family="Arial" font-size="8" fill="#000000">Red algae, Green algae, Glaucophytes — primary plastids</text>
  <text x="154" y="294" font-family="Arial" font-size="8" fill="#000000">Ancestral to land plants (Embryophyta)</text>

  <!-- ── OPISTHOKONTA (brief) ── -->
  <rect x="100" y="316" width="300" height="40" rx="8" fill="none" stroke="#000000" stroke-width="4" stroke-dasharray="6,3"/>
  <text x="174" y="334" font-family="Arial" font-size="10" font-weight="bold" fill="#000000">Opisthokonta</text>
  <text x="124" y="348" font-family="Arial" font-size="8" fill="#000000">Choanoflagellates (protist), Fungi, Animals — posterior flagellum</text>

  <!-- Paraphyletic note -->
  <rect x="60" y="372" width="376" height="36" rx="5" fill="none" stroke="#000000" stroke-width="2.5" stroke-dasharray="4,3"/>
  <text x="100" y="386" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Key: "Protists" are all eukaryotes excluding plants, fungi, animals</text>
  <text x="78" y="400" font-family="Arial" font-size="8" fill="#000000">Not monophyletic — multiple independent lineages; defined by exclusion</text>

  <!-- Eukaryote common ancestor -->
  <ellipse cx="250" cy="440" rx="60" ry="14" fill="none" stroke="#000000" stroke-width="3.5"/>
  <text x="198" y="444" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Last Eukaryotic Common Ancestor</text>
  <line x1="250" y1="426" x2="250" y2="414" stroke="#000000" stroke-width="2.5"/>
  <polygon points="246,416 250,406 254,416" fill="#000000"/>
</svg>`;

