  // ─── 19. MICROBIAL LOOP ────────────────────────────────────────────────────
  static microbialLoopDOMBacteriaFlagellatesCiliatesmZooplanktonFlowDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg fill="#000000" version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 500 460" enable-background="new 0 0 500 460" xml:space="preserve">

  <!-- Title -->
  <text x="90" y="20" font-family="Arial" font-size="12" font-weight="bold" fill="#000000">Microbial Loop — Aquatic Carbon Flow</text>

  <!-- ── Nodes ── -->
  <!-- Phytoplankton (top-left) -->
  <ellipse cx="100" cy="80" rx="60" ry="28" fill="none" stroke="#000000" stroke-width="4.5"/>
  <text x="56" y="76" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Phytoplankton</text>
  <text x="72" y="88" font-family="Arial" font-size="8" fill="#000000">(primary prod.)</text>

  <!-- DOM pool (centre-left) -->
  <ellipse cx="100" cy="196" rx="60" ry="28" fill="none" stroke="#000000" stroke-width="4.5"/>
  <text x="68" y="192" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Dissolved OM</text>
  <text x="76" y="204" font-family="Arial" font-size="8" fill="#000000">(DOM / DOC)</text>

  <!-- Bacteria (centre) -->
  <ellipse cx="260" cy="196" rx="60" ry="28" fill="none" stroke="#000000" stroke-width="4.5"/>
  <text x="224" y="192" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Heterotrophic</text>
  <text x="232" y="204" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Bacteria</text>

  <!-- Nanoflagellates (lower-centre) -->
  <ellipse cx="260" cy="300" rx="68" ry="28" fill="none" stroke="#000000" stroke-width="4.5"/>
  <text x="212" y="296" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Heterotrophic</text>
  <text x="208" y="308" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Nanoflagellates</text>

  <!-- Ciliates (right) -->
  <ellipse cx="410" cy="248" rx="60" ry="28" fill="none" stroke="#000000" stroke-width="4.5"/>
  <text x="386" y="244" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Ciliates</text>
  <text x="378" y="256" font-family="Arial" font-size="8" fill="#000000">(microzooplankton)</text>

  <!-- Mesozooplankton (top-right) -->
  <ellipse cx="400" cy="120" rx="68" ry="28" fill="none" stroke="#000000" stroke-width="4.5"/>
  <text x="352" y="116" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Mesozooplankton</text>
  <text x="364" y="128" font-family="Arial" font-size="8" fill="#000000">(copepods etc.)</text>

  <!-- Viruses (small, top-centre) -->
  <ellipse cx="260" cy="80" rx="40" ry="22" fill="none" stroke="#000000" stroke-width="3.5" stroke-dasharray="5,3"/>
  <text x="236" y="76" font-family="Arial" font-size="8.5" font-weight="bold" fill="#000000">Viruses</text>
  <text x="232" y="88" font-family="Arial" font-size="7.5" fill="#000000">(viral loop)</text>

  <!-- ── Arrows ── -->
  <!-- Phytoplankton exudate → DOM -->
  <line x1="100" y1="108" x2="100" y2="168" stroke="#000000" stroke-width="3"/>
  <polygon points="96,166 100,178 104,166" fill="#000000"/>
  <text x="6" y="142" font-family="Arial" font-size="7.5" fill="#000000">exudate / lysis</text>

  <!-- DOM → Bacteria -->
  <line x1="160" y1="196" x2="200" y2="196" stroke="#000000" stroke-width="3.5"/>
  <polygon points="198,192 208,196 198,200" fill="#000000"/>
  <text x="164" y="190" font-family="Arial" font-size="7.5" fill="#000000">uptake</text>

  <!-- Bacteria → Nanoflagellates (grazing) -->
  <line x1="260" y1="224" x2="260" y2="272" stroke="#000000" stroke-width="3.5"/>
  <polygon points="256,270 260,282 264,270" fill="#000000"/>
  <text x="264" y="256" font-family="Arial" font-size="7.5" fill="#000000">grazing</text>

  <!-- Nanoflagellates → Ciliates -->
  <line x1="328" y1="300" x2="376" y2="268" stroke="#000000" stroke-width="3.5"/>
  <polygon points="372,265 383,270 376,278" fill="#000000"/>
  <text x="338" y="292" font-family="Arial" font-size="7.5" fill="#000000">grazing</text>

  <!-- Ciliates → Mesozooplankton -->
  <line x1="410" y1="220" x2="408" y2="148" stroke="#000000" stroke-width="3.5"/>
  <polygon points="404,150 408,138 412,150" fill="#000000"/>
  <text x="414" y="188" font-family="Arial" font-size="7.5" fill="#000000">ingestion</text>

  <!-- Mesozooplankton → Phytoplankton feedback (nutrient recycling) -->
  <path d="M340,112 C280,80 200,60 162,70" fill="none" stroke="#000000" stroke-width="2.5" stroke-dasharray="6,3"/>
  <polygon points="164,66 154,73 162,80" fill="#000000"/>
  <text x="220" y="58" font-family="Arial" font-size="7.5" fill="#000000">nutrient recycling</text>

  <!-- Viruses → Bacteria (infection / lysis) -->
  <line x1="260" y1="102" x2="260" y2="168" stroke="#000000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <polygon points="256,166 260,178 264,166" fill="#000000"/>
  <text x="264" y="138" font-family="Arial" font-size="7.5" fill="#000000">lysis</text>

  <!-- Phytoplankton → Viruses -->
  <line x1="155" y1="78" x2="220" y2="78" stroke="#000000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <polygon points="218,74 228,78 218,82" fill="#000000"/>

  <!-- Bacteria → DOM (via viral lysis loop) -->
  <path d="M220,208 C180,220 160,220 160,208" fill="none" stroke="#000000" stroke-width="2" stroke-dasharray="4,3"/>
  <polygon points="156,206 160,216 164,206" fill="#000000"/>
  <text x="160" y="236" font-family="Arial" font-size="7.5" fill="#000000">viral lysis</text>
  <text x="156" y="246" font-family="Arial" font-size="7.5" fill="#000000">→ DOM release</text>

  <!-- Phytoplankton → Mesozooplankton (direct) -->
  <line x1="160" y1="80" x2="332" y2="112" stroke="#000000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <polygon points="330,108 340,114 332,121" fill="#000000"/>
  <text x="200" y="92" font-family="Arial" font-size="7.5" fill="#000000">direct grazing</text>

  <!-- Ciliates → DOM (egestion/sloppy feeding) -->
  <path d="M378,264 C350,330 290,340 280,328" fill="none" stroke="#000000" stroke-width="2" stroke-dasharray="3,3"/>
  <polygon points="276,326 280,338 284,326" fill="#000000"/>

  <!-- Respiration CO2 escape (from bacteria + nanoflagellates) -->
  <line x1="300" y1="182" x2="320" y2="162" stroke="#000000" stroke-width="2" stroke-dasharray="3,2"/>
  <text x="318" y="158" font-family="Arial" font-size="7.5" fill="#000000">CO₂ resp.</text>
  <line x1="300" y1="290" x2="318" y2="270" stroke="#000000" stroke-width="2" stroke-dasharray="3,2"/>
  <text x="320" y="266" font-family="Arial" font-size="7.5" fill="#000000">CO₂ resp.</text>

  <!-- Summary box -->
  <rect x="10" y="370" width="480" height="78" rx="6" fill="none" stroke="#000000" stroke-width="3" stroke-dasharray="5,3"/>
  <text x="170" y="386" font-family="Arial" font-size="9" font-weight="bold" fill="#000000">Microbial Loop Summary</text>
  <text x="16" y="400" font-family="Arial" font-size="8" fill="#000000">DOM (from algal exudate, viral lysis, sloppy feeding) is recaptured by heterotrophic bacteria</text>
  <text x="16" y="413" font-family="Arial" font-size="8" fill="#000000">Bacteria grazed by nanoflagellates → ciliates → mesozooplankton: carbon channelled to classic food web</text>
  <text x="16" y="426" font-family="Arial" font-size="8" fill="#000000">Viral shunt returns bacterial biomass directly to DOM, short-circuiting the loop</text>
  <text x="16" y="439" font-family="Arial" font-size="8" fill="#000000">Key players: HNF (heterotrophic nanoflagellates), ciliates, bacteria, viruses — critical in oligotrophic oceans</text>
</svg>`;

